{
  "answer_status": "insufficient_evidence",
  "conclusion": "Les extraits ne traitent pas du régime général des comptes-titres ordinaires.",
  "justification_bullets": [
    "Les extraits concernent les FCC, l'actionnariat salarié et les non-résidents, pas le compte-titres ordinaire.",
    "Aucun extrait ne décrit le PFU ou le barème progressif pour les gains de cession de valeurs mobilières."
  ],
  "limits": "Seuls les extraits fournis sont utilisés; d'autres règles peuvent s'appliquer."
}

{
  "answer_status": "supported",
  "conclusion": "Détention à 95% au moins, directe ou indirecte, et option conjointe pour l'intégration.",
  "justification_bullets": [
    "La société mère doit détenir 95% au moins du capital des filiales, directement ou indirectement [1].",
    "La détention indirecte peut passer par des sociétés intermédiaires, y compris étrangères [1][3].",
    "Les sociétés doivent être soumises à l'IS en France et exercer l'option pour le groupe [2][7]."
  ],
  "limits": "Les extraits ne détaillent pas toutes les conditions (ex: durée d'exercice, alignement)."
}

{
  "answer_status": "supported",
  "conclusion": "Le barème progressif s'applique au revenu net imposable après division par le nombre de parts (1 pour un célibataire).",
  "justification_bullets": [
    "L'impôt est calculé selon un barème progressif par tranches de revenu [1].",
    "Le quotient familial divise le revenu imposable par le nombre de parts, fixé par l'article 194 CGI [1].",
    "Pour un célibataire sans enfant, le nombre de parts est de 1 [1]."
  ],
  "limits": "Les extraits ne fournissent pas les tranches et taux du barème pour l'année en cours."
}

{
  "answer_status": "supported",
  "conclusion": "TVA au taux normal de 8,5% applicable en Martinique pour prestations de services à un non-assujetti.",
  "justification_bullets": [
    "La Martinique applique un taux normal de TVA de 8,5% (extrait [1] et [2]).",
    "Le champ d'application des taux est identique à celui de la métropole (extrait [1]).",
    "La vente d'abonnement à un dictionnaire en ligne est une prestation de services imposable en France (extrait [6] non pertinent pour le taux)."
  ],
  "limits": "Les extraits ne précisent pas le taux applicable aux services numériques, mais le taux normal s'applique."
}
